     5→import 'dart:async';
     6→import 'dart:io';
     7→
     8→// Package imports:
     9→import 'package:dio/dio.dart';
    10→import 'package:fimber/fimber.dart';
    11→import 'package:path/path.dart';
    12→import 'package:path_provider/path_provider.dart';
    13→import 'package:riverpod_annotation/riverpod_annotation.dart';
    14→import 'package:synchronized/synchronized.dart';
    15→
    16→// Project imports:
    17→import 'package:baseball_detector_flutter/controllers/check_result.dart';
    18→import 'package:baseball_detector_flutter/controllers/resource_data_list_controller.dart';
    19→import 'package:baseball_detector_flutter/data/clients/static_file_client.dart';
    20→import 'package:baseball_detector_flutter/data/models/ball.dart';
    21→import 'package:baseball_detector_flutter/data/models/ball_info.dart';
    22→import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
    23→import 'package:baseball_detector_flutter/data/models/failure/failure_code.dart';
    24→import 'package:baseball_detector_flutter/data/models/local_video.dart';
    25→import 'package:baseball_detector_flutter/data/models/resource.dart';
    26→import 'package:baseball_detector_flutter/data/result.dart';
    27→import 'package:baseball_detector_flutter/providers/repository_provider.dart';
    28→
    29→part 'resource_data_detail_controller.g.dart';
    30→
    31→/// Controller managing detailed resource data including balls and video caching
    32→/// Handles both local video files and remote resources from API
    33→@riverpod
    34→class ResourceDataDetailController extends _$ResourceDataDetailController {
    35→  static final _fc =
    36→      failureCodeBuilder.category('CRDD'); // Controller-ResourceDataDetail
    37→  static final _logger = FimberLog('ResourceDataDetailController');
    38→  static final _client = StaticFileClient();
    39→
    40→  // Concurrency control for thread safety
    41→  final _lock = Lock();
    42→  final _videoCacheLocks = <String, Lock>{};
    43→  final _ballInfoFetches = <int, Future<Result<Failure, BallInfo>>>{};
    44→
    45→  // Local path resolution tracking
    46→  bool _isResolvingLocalPath = false;
    47→
    48→  // ============================================================================
    49→  // INITIALIZATION METHODS
    50→  // ============================================================================
    51→
    52→  /// Main build method - initializes resource data from local or remote source
    53→  /// Returns loading state for remote resources, immediate data for local videos
    54→  @override
    55→  AsyncValue<ResourceData> build({
    56→    required String teamId,
    57→    required String sessionId,
    58→    required String resourceId,
    59→  }) {
    60→    ref.watch(repositoryProvider);
    61→
    62→    // Try to load from local storage first (synchronous check)
    63→    final localResource = _tryLoadLocalResource(resourceId);
    64→    if (localResource != null) {
    65→      return AsyncValue.data(localResource);
    66→    }
    67→
    68→    // For remote resources, start async initialization
    69→    _initializeRemoteResourceData(teamId, sessionId, resourceId);
    70→    return const AsyncValue.loading();
    71→  }
    72→
    73→  /// Attempts to load resource from local video storage
    74→  /// Returns ResourceData if found, null if not available locally
    75→  ResourceData? _tryLoadLocalResource(String resourceId) {
    76→    try {
    77→      final localVideoStorage = LocalVideoStorage.getInstance();
    78→      final localVideo =
    79→          localVideoStorage.selectLocalVideoDataWhereTheIdIs(resourceId);
    80→
    81→      final localResourceData = localVideo.transformToResourceData();
    82→
    83→      // Schedule async path resolution if needed (non-blocking)
    84→      if (localVideo.absolutePath == null && !_isResolvingLocalPath) {
    85→        _resolveLocalVideoPathAsync(localVideo, resourceId);
    86→      }
    87→
    88→      return localResourceData;
    89→    } catch (e) {
    90→      // Local video not found or error accessing it
    91→      _logger.d('Local video not found for resourceId: $resourceId');
    92→    }
    93→    return null;
    94→  }
    95→
    96→  /// Asynchronously resolves local video absolute path without blocking initialization
    97→  void _resolveLocalVideoPathAsync(
    98→    LocalVideoData localVideo,
    99→    String resourceId,
   100→  ) async {
   101→    _lock.synchronized(() async {
   102→      if (_isResolvingLocalPath) return;
   103→      _isResolvingLocalPath = true;
   104→
   105→      try {
   106→        final dirPath = await LocalVideoData.getBaseDirectory();
   107→        localVideo.absolutePath = join(dirPath, localVideo.path);
   108→
   109→        // Update state with resolved path if still valid
   110→        if (state.hasValue) {
   111→          final updatedResourceData = localVideo.transformToResourceData();
   112→          state = AsyncValue.data(updatedResourceData);
   113→        }
   114→      } catch (e, stackTrace) {
   115→        _logger.e('Error resolving local video path',
   116→            ex: e, stacktrace: stackTrace);
   117→        if (state.hasValue) {
   118→          state = AsyncValue.error(e, stackTrace);
   119→        }
   120→      } finally {
   121→        _isResolvingLocalPath = false;
   122→      }
   123→    });
   124→  }
   125→
   126→  /// Initializes remote resource data by fetching from API
   127→  void _initializeRemoteResourceData(
   128→    String teamId,
   129→    String sessionId,
   130→    String resourceId,
   131→  ) async {
   132→    try {
   133→      final resourceRes = await ref.read(repositoryProvider).getResourceDetail(
   134→            teamId: teamId,
   135→            sessionId: sessionId,
   136→            resourceId: resourceId,
   137→          );
   138→
   139→      checkResultForMaintenance(ref, resourceRes);
   140→
   141→      if (resourceRes.hasLeft) {
   142→        if (resourceRes.left is ForbiddenFailure) {
   143→          _logger.w(
   144→            'Failed to fetch resource detail for forbidden resource: $resourceId',
   145→            ex: resourceRes.left,
   146→          );
   147→        } else {
   148→          _logger.e(
   149→            'Failed to fetch resource detail: $resourceId',
   150→            ex: resourceRes.left,
   151→          );
   152→        }
   153→        state = AsyncValue.error(resourceRes.left, StackTrace.current);
   154→        return;
   155→      }
   156→
   157→      state = AsyncValue.data(resourceRes.right);
   158→    } catch (e, stackTrace) {
   159→      _logger.e('Unexpected error initializing remote resource data',
   160→          ex: e, stacktrace: stackTrace);
   161→      state = AsyncValue.error(e, stackTrace);
   162→    }
   163→  }
   164→
   165→  // ============================================================================
   166→  // BALL INFO MANAGEMENT METHODS
   167→  // ============================================================================
   168→
   169→  /// Combines ball data from getBall API (includes presignedAnnotatedVideoUrl)
   170→  /// with BallInfo.positions data from resource detail API to create complete ball information
   171→  /// Uses caching to prevent duplicate requests for the same ball
   172→  Future<Result<Failure, BallInfo>> getCompleteBallInfo(int ballId) async {
   173→    // Check if we already have a pending fetch for this ball
   174→    final existingFetch = _ballInfoFetches[ballId];
   175→    if (existingFetch != null) {
   176→      return await existingFetch;
   177→    }
   178→
   179→    // Create new fetch and store it to prevent duplicates
   180→    final fetchFuture = _performBallInfoFetch(ballId);
   181→    _ballInfoFetches[ballId] = fetchFuture;
   182→
   183→    try {
   184→      return await fetchFuture;
   185→    } finally {
   186→      // Clean up completed fetch
   187→      _ballInfoFetches.remove(ballId);
   188→    }
   189→  }
   190→
   191→  /// Performs the actual ball info fetch with proper error handling
   192→  /// Merges ball API data with existing position data from state
   193→  ///
   194→  /// We need BallInfo.positions and BallInfo.ball.presignedAnnotatedVideoUrl or BallInfo.ball.presignedExtractedVideoUrl
   195→  ///
   196→  /// [repositoryProvider.getResources]: Returns session's ResourceData which doesn't include BallInfo.positions and BallInfo.ball.presignedAnnotatedVideoUrl and BallInfo.ball.presignedExtractedVideoUrl
   197→  /// [repositoryProvider.getResourceDetail]: Returns a specific ResourceDAta which include BallInfo.positions but doesn't include BallInfo.ball.presignedAnnotatedVideoUrl and BallInfo.ball.presignedExtractedVideoUrl
   198→  /// [repositoryProvider.getBall]: Returns a specific BallInfo which include BallInfo.ball.presignedAnnotatedVideoUrl or BallInfo.ball.presignedExtractedVideoUrl
   199→  ///
   200→  /// So we need to call getBall to complete the BallInfo even though we already have BallInfo from getResourceDetail in [_initializeRemoteResourceData].
   201→  Future<Result<Failure, BallInfo>> _performBallInfoFetch(int ballId) async {
   202→    final methodFc = _fc.category('GCBI');
   203→
   204→    try {
   205→      // Validate current state
   206→      if (!state.hasValue) {
   207→        return Left(Failure.undefined(code: methodFc.position('001')));
   208→      }
   209→
   210→      // Check if we already have complete ball info in state
   211→      final existingBallInfo = _findBallInfoInState(ballId);
   212→      if (existingBallInfo != null && _isBallInfoComplete(existingBallInfo)) {
   213→        return Right(existingBallInfo);
   214→      }
   215→
   216→      // Fetch fresh ball data from API
   217→      final ballResult = await _fetchBallDataFromAPI(ballId);
   218→      if (ballResult.hasLeft) return Left(ballResult.left);
   219→
   220→      // Re-validate state after async operation
   221→      if (!state.hasValue) {
   222→        return Left(Failure.undefined(code: methodFc.position('004')));
   223→      }
   224→
   225→      // Get current ball info with position data
   226→      final currentBallInfo = _findBallInfoInState(ballId);
   227→      if (currentBallInfo == null) {
   228→        return Left(Failure.undefined(code: methodFc.position('003')));
   229→      }
   230→
   231→      // Merge API data with existing position data and update state
   232→      final completeBallInfo = currentBallInfo.copyWith(ball: ballResult.right);
   233→      await _updateBallInfoInState(ballId, completeBallInfo);
   234→
   235→      return Right(completeBallInfo);
   236→    } catch (e, stackTrace) {
   237→      _logger.e('Unexpected error in getCompleteBallInfo',
   238→          ex: e, stacktrace: stackTrace);
   239→      return Left(Failure.undefined(code: methodFc.position('002')));
   240→    }
   241→  }
   242→
   243→  /// Finds ball info in current state by ball ID
   244→  BallInfo? _findBallInfoInState(int ballId) {
   245→    if (!state.hasValue) return null;
   246→
   247→    try {
   248→      return state.value!.ballInfoList?.firstWhere(
   249→        (bi) => bi.ball.id == ballId,
   250→        orElse: () => throw StateError('BallInfo not found'),
   251→      );
   252→    } catch (e) {
   253→      return null;
   254→    }
   255→  }
   256→
   257→  /// Checks if ball info has all required data (including presigned video URL)
   258→  bool _isBallInfoComplete(BallInfo ballInfo) {
   259→    return ballInfo.ball.presignedAnnotatedVideoUrl != null ||
   260→        ballInfo.ball.presignedExtractedVideoUrl != null;
   261→  }
   262→
   263→  /// Fetches ball data from getBall API endpoint
   264→  Future<Result<Failure, Ball>> _fetchBallDataFromAPI(int ballId) async {
   265→    if (!state.hasValue) {
   266→      return Left(Failure.undefined(code: _fc.position('001')));
   267→    }
   268→
   269→    final resourceData = state.value!;
   270→    final ballRes = await ref.read(repositoryProvider).getBall(
   271→          teamId: resourceData.teamId!,
   272→          sessionId: resourceData.sessionId!,
   273→          resourceId: resourceData.id!,
   274→          ballId: ballId,
   275→        );
   276→
   277→    checkResultForMaintenance(ref, ballRes);
   278→
   279→    if (ballRes.hasLeft) {
   280→      _logger.e('Failed to fetch ball data for ballId: $ballId');
   281→      return Left(ballRes.left);
   282→    }
   283→
   284→    return Right(ballRes.right);
   285→  }
   286→
   287→  /// Returns cached ball info or fetches from API if not available or incomplete
   288→  Future<Result<Failure, BallInfo>> getCachedOrFetchBallInfo(int ballId) async {
   289→    final existingBallInfo = _findBallInfoInState(ballId);
   290→
   291→    if (existingBallInfo != null && _isBallInfoComplete(existingBallInfo)) {
   292→      return Right(existingBallInfo);
   293→    }
   294→
   295→    return await getCompleteBallInfo(ballId);
   296→  }
   297→
   298→  // ============================================================================
   299→  // BALL MODIFICATION METHODS
   300→  // ============================================================================
   301→
   302→  /// Updates pitch type for a ball and refreshes the state
   303→  Future<Result<Failure, void>> editPitchType(
   304→    int ballId,
   305→    String? pitchTypeId,
   306→  ) async {
   307→    if (!state.hasValue) {
   308→      return Left(Failure.undefined(code: _fc.position('001')));
   309→    }
   310→
   311→    final resourceData = state.value!;
   312→    final res = await ref.read(repositoryProvider).editPitchType(
   313→          sessionId: resourceData.sessionId!,
   314→          resourceId: resourceData.id!,
   315→          ballId: ballId,
   316→          pitchTypeId: pitchTypeId,
   317→        );
   318→
   319→    checkResultForMaintenance(ref, res);
   320→
   321→    // Update local state if API call succeeded
   322→    if (res.hasRight) {
   323→      final existingBallInfo = _findBallInfoInState(ballId);
   324→      if (existingBallInfo != null) {
   325→        await _updateBallInfoInState(
   326→          ballId,
   327→          existingBallInfo.copyWith(ball: res.right.ball),
   328→        );
   329→
   330→        // Also update the resource list controller to keep session_details_page in sync
   331→        ref
   332→            .read(resourceDataListControllerProvider(
   333→              teamId: resourceData.teamId!,
   334→              sessionId: resourceData.sessionId!,
   335→            ).notifier)
   336→            .updateSpecificPitchType(
   337→              resourceId: resourceData.id!,
   338→              ball: res.right.ball,
   339→            );
   340→      }
   341→    }
   342→
   343→    return res;
   344→  }
   345→
   346→  /// Deletes a ball and removes it from local state
   347→  Future<Result<Failure, void>> deleteBall(int ballId) async {
   348→    if (!state.hasValue) {
   349→      return Left(Failure.undefined(code: _fc.position('001')));
   350→    }
   351→
   352→    final resourceData = state.value!;
   353→    final res = await ref.read(repositoryProvider).deleteBall(
   354→          sessionId: resourceData.sessionId!,
   355→          resourceId: resourceData.id!,
   356→          ballId: ballId,
   357→        );
   358→
   359→    // Remove from local state if API call succeeded
   360→    if (res.hasRight && state.hasValue) {
   361→      await _removeBallFromState(ballId);
   362→
   363→      // Also update the resource list controller to keep session_details_page in sync
   364→      ref
   365→          .read(resourceDataListControllerProvider(
   366→            teamId: resourceData.teamId!,
   367→            sessionId: resourceData.sessionId!,
   368→          ).notifier)
   369→          .removeBallFromResource(
   370→            resourceId: resourceData.id!,
   371→            ballId: ballId,
   372→          );
   373→    }
   374→
   375→    return res;
   376→  }
   377→
   378→  /// Removes ball from the current state
   379→  Future<void> _removeBallFromState(int ballId) async {
   380→    await _lock.synchronized(() async {
   381→      if (!state.hasValue) return;
   382→
   383→      final currentResourceData = state.value!;
   384→      final updatedBallInfoList = currentResourceData.ballInfoList
   385→          ?.where((bi) => bi.ball.id != ballId)
   386→          .toList();
   387→
   388→      final updatedResourceData = currentResourceData.copyWith(
   389→        ballInfoList: updatedBallInfoList,
   390→      );
   391→
   392→      state = AsyncValue.data(updatedResourceData);
   393→    });
   394→  }
   395→
   396→  // ============================================================================
   397→  // VIDEO ANALYSIS METHODS
   398→  // ============================================================================
   399→
   400→  /// Triggers re-analysis of the video and reinitializes resource data
   401→  Future<Result<Failure, void>> reAnalyzeVideo() async {
   402→    final res = await ref.read(repositoryProvider).reAnalyzeVideo(
   403→          sessionId: sessionId,
   404→          resourceId: resourceId,
   405→        );
   406→
   407→    checkResultForMaintenance(ref, res);
   408→    return res;
   409→  }
   410→
   411→  // ============================================================================
   412→  // VIDEO CACHING METHODS
   413→  // ============================================================================
   414→
   415→  /// Caches video file locally if needed, with fallback to resource-level video
   416→  /// Returns local file path if cached successfully, or URL for streaming
   417→  /// Supports progress tracking and cancellation for downloads
   418→  Future<Result<Failure, String>> cacheVideoIfNeeded({
   419→    required int ballId,
   420→    CancelToken? cancelToken,
   421→    void Function(double)? onProgress,
   422→  }) async {
   423→    final methodFc = _fc.category('CVIN');
   424→
   425→    if (!state.hasValue) {
   426→      return Left(Failure.undefined(code: methodFc.position('001')));
   427→    }
   428→
   429→    final resourceData = state.value!;
   430→
   431→    // Use local video file if available (highest priority)
   432→    if (resourceData.pathVideoOnLocal != null) {
   433→      return Right(resourceData.pathVideoOnLocal!);
   434→    }
   435→
   436→    // Determine video URL to cache
   437→    final urlResult = await _determineVideoUrl(ballId, methodFc);
   438→    if (urlResult.hasLeft) return Left(urlResult.left);
   439→
   440→    final (url, hasBallSpecificVideo) = urlResult.right;
   441→
   442→    // Skip caching for not-analyzed resources (stream directly)
   443→    if (resourceData.statusType != ResourceStatusType.analysisSucceeded) {
   444→      return Right(url);
   445→    }
   446→
   447→    // Cache the video with concurrency control
   448→    return await _cacheVideoWithLock(
   449→        url, ballId, hasBallSpecificVideo, methodFc, cancelToken, onProgress);
   450→  }
   451→
   452→  /// Determines the appropriate video URL (ball-specific or resource fallback)
   453→  /// Returns tuple of (videoUrl, hasBallSpecificVideo)
   454→  Future<Result<Failure, (String, bool)>> _determineVideoUrl(
   455→    int ballId,
   456→    FailureCodeBuilder fc,
   457→  ) async {
   458→    if (!state.hasValue) {
   459→      return Left(Failure.undefined(code: fc.position('001')));
   460→    }
