   554→        join((await getApplicationCacheDirectory()).path, 'videos');
   555→    final ext = extension(Uri.parse(url).pathSegments.last).toLowerCase();
   556→    final fileName = hasBallSpecificVideo
   557→        ? '${resourceData.id}_ball$ballId$ext'
   558→        : '${resourceData.id}$ext';
