/// {@category Controllers}
library;

// Dart imports:
import 'dart:async';
import 'dart:io';

// Package imports:
import 'package:dio/dio.dart';
import 'package:fimber/fimber.dart';
import 'package:path/path.dart';
import 'package:path_provider/path_provider.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';
import 'package:synchronized/synchronized.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/check_result.dart';
import 'package:baseball_detector_flutter/controllers/resource_data_list_controller.dart';
import 'package:baseball_detector_flutter/data/clients/static_file_client.dart';
import 'package:baseball_detector_flutter/data/models/ball.dart';
import 'package:baseball_detector_flutter/data/models/ball_info.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure_code.dart';
import 'package:baseball_detector_flutter/data/models/local_video.dart';
import 'package:baseball_detector_flutter/data/models/resource.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/providers/repository_provider.dart';

part 'resource_data_detail_controller.g.dart';

/// Controller managing detailed resource data including balls and video caching
/// Handles both local video files and remote resources from API
@riverpod
class ResourceDataDetailController extends _$ResourceDataDetailController {
  static final _fc =
      failureCodeBuilder.category('CRDD'); // Controller-ResourceDataDetail
  static final _logger = FimberLog('ResourceDataDetailController');
  static final _client = StaticFileClient();

  // Concurrency control for thread safety
  final _lock = Lock();
  final _videoCacheLocks = <String, Lock>{};
  final _ballInfoFetches = <int, Future<Result<Failure, BallInfo>>>{};

  // Local path resolution tracking
  bool _isResolvingLocalPath = false;

  // ============================================================================
  // INITIALIZATION METHODS
  // ============================================================================

  /// Main build method - initializes resource data from local or remote source
  /// Returns loading state for remote resources, immediate data for local videos
  @override
  AsyncValue<ResourceData> build({
    required String teamId,
    required String sessionId,
    required String resourceId,
  }) {
    ref.watch(repositoryProvider);

    // Try to load from local storage first (synchronous check)
    final localResource = _tryLoadLocalResource(resourceId);
    if (localResource != null) {
      return AsyncValue.data(localResource);
    }

    // For remote resources, start async initialization
    _initializeRemoteResourceData(teamId, sessionId, resourceId);
    return const AsyncValue.loading();
  }

  /// Attempts to load resource from local video storage
  /// Returns ResourceData if found, null if not available locally
  ResourceData? _tryLoadLocalResource(String resourceId) {
    try {
      final localVideoStorage = LocalVideoStorage.getInstance();
      final localVideo =
          localVideoStorage.selectLocalVideoDataWhereTheIdIs(resourceId);

      final localResourceData = localVideo.transformToResourceData();

      // Schedule async path resolution if needed (non-blocking)
      if (localVideo.absolutePath == null && !_isResolvingLocalPath) {
        _resolveLocalVideoPathAsync(localVideo, resourceId);
      }

      return localResourceData;
    } catch (e) {
      // Local video not found or error accessing it
      _logger.d('Local video not found for resourceId: $resourceId');
    }
    return null;
  }

  /// Asynchronously resolves local video absolute path without blocking initialization
  void _resolveLocalVideoPathAsync(
    LocalVideoData localVideo,
    String resourceId,
  ) async {
    _lock.synchronized(() async {
      if (_isResolvingLocalPath) return;
      _isResolvingLocalPath = true;

      try {
        final dirPath = await LocalVideoData.getBaseDirectory();
        localVideo.absolutePath = join(dirPath, localVideo.path);

        // Update state with resolved path if still valid
        if (state.hasValue) {
          final updatedResourceData = localVideo.transformToResourceData();
          state = AsyncValue.data(updatedResourceData);
        }
      } catch (e, stackTrace) {
        _logger.e('Error resolving local video path',
            ex: e, stacktrace: stackTrace);
        if (state.hasValue) {
          state = AsyncValue.error(e, stackTrace);
        }
      } finally {
        _isResolvingLocalPath = false;
      }
    });
  }

  /// Initializes remote resource data by fetching from API
  void _initializeRemoteResourceData(
    String teamId,
    String sessionId,
    String resourceId,
  ) async {
    try {
      final resourceRes = await ref.read(repositoryProvider).getResourceDetail(
            teamId: teamId,
            sessionId: sessionId,
            resourceId: resourceId,
          );

      checkResultForMaintenance(ref, resourceRes);

      if (resourceRes.hasLeft) {
        if (resourceRes.left is ForbiddenFailure) {
          _logger.w(
            'Failed to fetch resource detail for forbidden resource: $resourceId',
            ex: resourceRes.left,
          );
        } else {
          _logger.e(
            'Failed to fetch resource detail: $resourceId',
            ex: resourceRes.left,
          );
        }
        state = AsyncValue.error(resourceRes.left, StackTrace.current);
        return;
      }

      state = AsyncValue.data(resourceRes.right);
    } catch (e, stackTrace) {
      _logger.e('Unexpected error initializing remote resource data',
          ex: e, stacktrace: stackTrace);
      state = AsyncValue.error(e, stackTrace);
    }
  }

  // ============================================================================
  // BALL INFO MANAGEMENT METHODS
  // ============================================================================

  /// Combines ball data from getBall API (includes presignedAnnotatedVideoUrl)
  /// with BallInfo.positions data from resource detail API to create complete ball information
  /// Uses caching to prevent duplicate requests for the same ball
  Future<Result<Failure, BallInfo>> getCompleteBallInfo(int ballId) async {
    // Check if we already have a pending fetch for this ball
    final existingFetch = _ballInfoFetches[ballId];
    if (existingFetch != null) {
      return await existingFetch;
    }

    // Create new fetch and store it to prevent duplicates
    final fetchFuture = _performBallInfoFetch(ballId);
    _ballInfoFetches[ballId] = fetchFuture;

    try {
      return await fetchFuture;
    } finally {
      // Clean up completed fetch
      _ballInfoFetches.remove(ballId);
    }
  }

  /// Performs the actual ball info fetch with proper error handling
  /// Merges ball API data with existing position data from state
  ///
  /// We need BallInfo.positions and BallInfo.ball.presignedAnnotatedVideoUrl or BallInfo.ball.presignedExtractedVideoUrl
  ///
  /// [repositoryProvider.getResources]: Returns session's ResourceData which doesn't include BallInfo.positions and BallInfo.ball.presignedAnnotatedVideoUrl and BallInfo.ball.presignedExtractedVideoUrl
  /// [repositoryProvider.getResourceDetail]: Returns a specific ResourceDAta which include BallInfo.positions but doesn't include BallInfo.ball.presignedAnnotatedVideoUrl and BallInfo.ball.presignedExtractedVideoUrl
  /// [repositoryProvider.getBall]: Returns a specific BallInfo which include BallInfo.ball.presignedAnnotatedVideoUrl or BallInfo.ball.presignedExtractedVideoUrl
  ///
  /// So we need to call getBall to complete the BallInfo even though we already have BallInfo from getResourceDetail in [_initializeRemoteResourceData].
  Future<Result<Failure, BallInfo>> _performBallInfoFetch(int ballId) async {
    final methodFc = _fc.category('GCBI');

    try {
      // Validate current state
      if (!state.hasValue) {
        return Left(Failure.undefined(code: methodFc.position('001')));
      }

      // Check if we already have complete ball info in state
      final existingBallInfo = _findBallInfoInState(ballId);
      if (existingBallInfo != null && _isBallInfoComplete(existingBallInfo)) {
        return Right(existingBallInfo);
      }

      // Fetch fresh ball data from API
      final ballResult = await _fetchBallDataFromAPI(ballId);
      if (ballResult.hasLeft) return Left(ballResult.left);

      // Re-validate state after async operation
      if (!state.hasValue) {
        return Left(Failure.undefined(code: methodFc.position('004')));
      }

      // Get current ball info with position data
      final currentBallInfo = _findBallInfoInState(ballId);
      if (currentBallInfo == null) {
        return Left(Failure.undefined(code: methodFc.position('003')));
      }

      // Merge API data with existing position data and update state
      final completeBallInfo = currentBallInfo.copyWith(ball: ballResult.right);
      await _updateBallInfoInState(ballId, completeBallInfo);

      return Right(completeBallInfo);
    } catch (e, stackTrace) {
      _logger.e('Unexpected error in getCompleteBallInfo',
          ex: e, stacktrace: stackTrace);
      return Left(Failure.undefined(code: methodFc.position('002')));
    }
  }

  /// Finds ball info in current state by ball ID
  BallInfo? _findBallInfoInState(int ballId) {
    if (!state.hasValue) return null;

    try {
      return state.value!.ballInfoList?.firstWhere(
        (bi) => bi.ball.id == ballId,
        orElse: () => throw StateError('BallInfo not found'),
      );
    } catch (e) {
      return null;
    }
  }

  /// Checks if ball info has all required data (including presigned video URL)
  bool _isBallInfoComplete(BallInfo ballInfo) {
    return ballInfo.ball.presignedAnnotatedVideoUrl != null ||
        ballInfo.ball.presignedExtractedVideoUrl != null;
  }

  /// Fetches ball data from getBall API endpoint
  Future<Result<Failure, Ball>> _fetchBallDataFromAPI(int ballId) async {
    if (!state.hasValue) {
      return Left(Failure.undefined(code: _fc.position('001')));
    }

    final resourceData = state.value!;
    final ballRes = await ref.read(repositoryProvider).getBall(
          teamId: resourceData.teamId!,
          sessionId: resourceData.sessionId!,
          resourceId: resourceData.id!,
          ballId: ballId,
        );

    checkResultForMaintenance(ref, ballRes);

    if (ballRes.hasLeft) {
      _logger.e('Failed to fetch ball data for ballId: $ballId');
      return Left(ballRes.left);
    }

    return Right(ballRes.right);
  }

  /// Returns cached ball info or fetches from API if not available or incomplete
  Future<Result<Failure, BallInfo>> getCachedOrFetchBallInfo(int ballId) async {
    final existingBallInfo = _findBallInfoInState(ballId);

    if (existingBallInfo != null && _isBallInfoComplete(existingBallInfo)) {
      return Right(existingBallInfo);
    }

    return await getCompleteBallInfo(ballId);
  }

  // ============================================================================
  // BALL MODIFICATION METHODS
  // ============================================================================

  /// Updates pitch type for a ball and refreshes the state
  Future<Result<Failure, void>> editPitchType(
    int ballId,
    String? pitchTypeId,
  ) async {
    if (!state.hasValue) {
      return Left(Failure.undefined(code: _fc.position('001')));
    }

    final resourceData = state.value!;
    final res = await ref.read(repositoryProvider).editPitchType(
          sessionId: resourceData.sessionId!,
          resourceId: resourceData.id!,
          ballId: ballId,
          pitchTypeId: pitchTypeId,
        );

    checkResultForMaintenance(ref, res);

    // Update local state if API call succeeded
    if (res.hasRight) {
      final existingBallInfo = _findBallInfoInState(ballId);
      if (existingBallInfo != null) {
        await _updateBallInfoInState(
          ballId,
          existingBallInfo.copyWith(ball: res.right.ball),
        );

        // Also update the resource list controller to keep session_details_page in sync
        ref
            .read(resourceDataListControllerProvider(
              teamId: resourceData.teamId!,
              sessionId: resourceData.sessionId!,
            ).notifier)
            .updateSpecificPitchType(
              resourceId: resourceData.id!,
              ball: res.right.ball,
            );
      }
    }

    return res;
  }

  /// Deletes a ball and removes it from local state
  Future<Result<Failure, void>> deleteBall(int ballId) async {
    if (!state.hasValue) {
      return Left(Failure.undefined(code: _fc.position('001')));
    }

    final resourceData = state.value!;
    final res = await ref.read(repositoryProvider).deleteBall(
          sessionId: resourceData.sessionId!,
          resourceId: resourceData.id!,
          ballId: ballId,
        );

    // Remove from local state if API call succeeded
    if (res.hasRight && state.hasValue) {
      await _removeBallFromState(ballId);

      // Also update the resource list controller to keep session_details_page in sync
      ref
          .read(resourceDataListControllerProvider(
            teamId: resourceData.teamId!,
            sessionId: resourceData.sessionId!,
          ).notifier)
          .removeBallFromResource(
            resourceId: resourceData.id!,
            ballId: ballId,
          );
    }

    return res;
  }

  /// Removes ball from the current state
  Future<void> _removeBallFromState(int ballId) async {
    await _lock.synchronized(() async {
      if (!state.hasValue) return;

      final currentResourceData = state.value!;
      final updatedBallInfoList = currentResourceData.ballInfoList
          ?.where((bi) => bi.ball.id != ballId)
          .toList();

      final updatedResourceData = currentResourceData.copyWith(
        ballInfoList: updatedBallInfoList,
      );

      state = AsyncValue.data(updatedResourceData);
    });
  }

  // ============================================================================
  // VIDEO ANALYSIS METHODS
  // ============================================================================

  /// Triggers re-analysis of the video and reinitializes resource data
  Future<Result<Failure, void>> reAnalyzeVideo() async {
    final res = await ref.read(repositoryProvider).reAnalyzeVideo(
          sessionId: sessionId,
          resourceId: resourceId,
        );

    checkResultForMaintenance(ref, res);
    return res;
  }

  // ============================================================================
  // VIDEO CACHING METHODS
  // ============================================================================

  /// Caches video file locally if needed, with fallback to resource-level video
  /// Returns local file path if cached successfully, or URL for streaming
  /// Supports progress tracking and cancellation for downloads
  Future<Result<Failure, String>> cacheVideoIfNeeded({
    required int ballId,
    CancelToken? cancelToken,
    void Function(double)? onProgress,
  }) async {
    final methodFc = _fc.category('CVIN');

    if (!state.hasValue) {
      return Left(Failure.undefined(code: methodFc.position('001')));
    }

    final resourceData = state.value!;

    // Use local video file if available (highest priority)
    if (resourceData.pathVideoOnLocal != null) {
      return Right(resourceData.pathVideoOnLocal!);
    }

    // Determine video URL to cache
    final urlResult = await _determineVideoUrl(ballId, methodFc);
    if (urlResult.hasLeft) return Left(urlResult.left);

    final (url, hasBallSpecificVideo) = urlResult.right;

    // Skip caching for not-analyzed resources (stream directly)
    if (resourceData.statusType != ResourceStatusType.analysisSucceeded) {
      return Right(url);
    }

    // Cache the video with concurrency control
    return await _cacheVideoWithLock(
        url, ballId, hasBallSpecificVideo, methodFc, cancelToken, onProgress);
  }

  /// Determines the appropriate video URL (ball-specific or resource fallback)
  /// Returns tuple of (videoUrl, hasBallSpecificVideo)
  Future<Result<Failure, (String, bool)>> _determineVideoUrl(
    int ballId,
    FailureCodeBuilder fc,
  ) async {
    if (!state.hasValue) {
      return Left(Failure.undefined(code: fc.position('001')));
    }

    final resourceData = state.value!;
    final ballInfoResult = await getCachedOrFetchBallInfo(ballId);

    // If ball info fetch failed, use resource-level URLs as fallback
    if (ballInfoResult.hasLeft) {
      final resourceUrl = resourceData.presignedOriginalVideoUrl;

      if (resourceUrl == null) {
        _logger.e('No video URL available for resource: ${resourceData.id}');
        return Left(Failure.undefined(code: fc.position('003')));
      }

      return Right((resourceUrl, false));
    }

    final ball = ballInfoResult.right.ball;
    final hasBallSpecificVideo = ball.presignedAnnotatedVideoUrl != null ||
        ball.presignedExtractedVideoUrl != null;

    // Prefer ball-specific video if available
    if (hasBallSpecificVideo) {
      // For dev,stg, ball contains presignedAnnotatedVideoUrl and presignedExtractedVideoUrl.
      // For prd, ball contains only presignedExtractedVideoUrl.
      final specificUrl =
          ball.presignedAnnotatedVideoUrl ?? ball.presignedExtractedVideoUrl;
      return Right((specificUrl!, true));
    }

    // Fallback to resource-level URLs
    final fallbackUrl = resourceData.presignedOriginalVideoUrl;

    if (fallbackUrl == null) {
      _logger.e('No fallback URL available for resource: ${resourceData.id}');
      return Left(Failure.undefined(code: fc.position('003')));
    }

    return Right((fallbackUrl, false));
  }

  /// Caches video with proper concurrency control to prevent duplicate downloads
  Future<Result<Failure, String>> _cacheVideoWithLock(
    String url,
    int ballId,
    bool hasBallSpecificVideo,
    FailureCodeBuilder fc,
    CancelToken? cancelToken,
    void Function(double)? onProgress,
  ) async {
    if (!state.hasValue) {
      return Left(Failure.undefined(code: fc.position('001')));
    }

    final resourceData = state.value!;

    // Create unique cache key for this video
    final cacheKey = hasBallSpecificVideo
        ? '${resourceData.id}_ball$ballId'
        : '${resourceData.id}';

    // Get or create lock for this cache key to prevent concurrent downloads
    final cacheLock = _videoCacheLocks.putIfAbsent(cacheKey, () => Lock());

    try {
      return await cacheLock.synchronized(() async {
        return await _performVideoCaching(
            url, ballId, hasBallSpecificVideo, fc, cancelToken, onProgress);
      });
    } finally {
      // Clean up lock if no longer needed
      if (_videoCacheLocks[cacheKey]?.locked == false) {
        _videoCacheLocks.remove(cacheKey);
      }
    }
  }

  /// Performs the actual video caching operation
  Future<Result<Failure, String>> _performVideoCaching(
    String url,
    int ballId,
    bool hasBallSpecificVideo,
    FailureCodeBuilder fc,
    CancelToken? cancelToken,
    void Function(double)? onProgress,
  ) async {
    if (!state.hasValue) {
      return Left(Failure.undefined(code: fc.position('001')));
    }

    final resourceData = state.value!;

    // Prepare cache directory and filename
    final cacheDir =
        join((await getApplicationCacheDirectory()).path, 'videos');
    final ext = extension(Uri.parse(url).pathSegments.last).toLowerCase();
    final fileName = hasBallSpecificVideo
        ? '${resourceData.id}_ball$ballId$ext'
        : '${resourceData.id}$ext';

    return await _downloadVideoToCache(
        url, cacheDir, fileName, fc, cancelToken, onProgress);
  }

  /// Downloads video file to cache with progress tracking and error handling
  Future<Result<Failure, String>> _downloadVideoToCache(
    String url,
    String directory,
    String fileName,
    FailureCodeBuilder fc,
    CancelToken? cancelToken,
    void Function(double)? onProgress,
  ) async {
    final methodFc = fc.category('CV');
    final cachePath = join(directory, fileName);

    // Return immediately if already cached
    if (await File(cachePath).exists()) {
      return Right(cachePath);
    }

    try {
      final result = await _client.saveAsFile(
        url: url,
        savePath: cachePath,
        cancelToken: cancelToken,
        onProgress: onProgress,
      );

      if (result.hasLeft) {
        return _handleDownloadError(result.left, methodFc, url);
      }

      return Right(cachePath);
    } catch (e, stackTrace) {
      _logger.e('Unexpected error downloading video',
          ex: e, stacktrace: stackTrace);
      return Left(Failure.undefined(code: methodFc.position('002')));
    }
  }

  /// Handles different types of download errors with appropriate responses
  Result<Failure, String> _handleDownloadError(
    Failure error,
    FailureCodeBuilder fc,
    String url,
  ) {
    // Preserve cancellation errors as-is
    if (error is RequestCancelledFailure) {
      return Left(error);
    }

    // Handle 403 Forbidden with specific error message
    if (error is HttpResponseFailure && error.status == 403) {
      return Left(Failure.httpResponse(
        code: fc.position('001'),
        status: 403,
        description: (l10n) => l10n.resource_data_detail_controller__forbidden,
      ));
    }

    // Log and return other errors
    _logger.e('Failed to download video', ex: error);
    return Left(error);
  }

  // ============================================================================
  // STATE MANAGEMENT METHODS
  // ============================================================================

  /// Updates ball info in the ResourceData state with proper synchronization
  Future<void> _updateBallInfoInState(
    int ballId,
    BallInfo updatedBallInfo,
  ) async {
    await _lock.synchronized(() async {
      if (!state.hasValue) return;

      final resourceData = state.value!;
      final updatedBallInfoList = resourceData.ballInfoList?.map((bi) {
        return bi.ball.id == ballId ? updatedBallInfo : bi;
      }).toList();

      final updatedResourceData = resourceData.copyWith(
        ballInfoList: updatedBallInfoList,
      );

      state = AsyncValue.data(updatedResourceData);
    });
  }
}

